--
-- Table structure for table `tb_albuns`
--

DROP TABLE IF EXISTS `tb_albuns`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_albuns` (
  `album_id` int NOT NULL AUTO_INCREMENT,
  `titulo` varchar(128) NOT NULL,
  `capa_url` varchar(2048) DEFAULT NULL,
  `artista_id` int NOT NULL,
  `gravadora_id` int DEFAULT '60',
  `data_lancamento` date DEFAULT NULL,
  `tipo_id` int DEFAULT NULL,
  `preco_sugerido` decimal(10,2) DEFAULT NULL,
  `situacao` int DEFAULT NULL,
  `criado_em` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `atualizado_em` timestamp NULL DEFAULT NULL,
  `deletado` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`album_id`),
  KEY `fk_album_artista_idx` (`artista_id`),
  KEY `fk_album_gravadora_idx` (`gravadora_id`),
  KEY `fk_album_tipo_idx` (`tipo_id`),
  KEY `fk_album_situacao_idx` (`situacao`),
  CONSTRAINT `fk_album_artista` FOREIGN KEY (`artista_id`) REFERENCES `tb_artistas` (`artista_id`),
  CONSTRAINT `fk_album_gravadora` FOREIGN KEY (`gravadora_id`) REFERENCES `tb_gravadoras` (`gravadora_id`) ON UPDATE CASCADE,
  CONSTRAINT `fk_album_situacao` FOREIGN KEY (`situacao`) REFERENCES `tb_situacoes` (`situacao_id`),
  CONSTRAINT `fk_album_tipo` FOREIGN KEY (`tipo_id`) REFERENCES `tb_tipos` (`tipo_id`)
) ENGINE=InnoDB AUTO_INCREMENT=7685 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

