--
-- Table structure for table `tb_artistas`
--

DROP TABLE IF EXISTS `tb_artistas`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_artistas` (
  `artista_id` int NOT NULL AUTO_INCREMENT,
  `nome` varchar(128) NOT NULL,
  `pais_origem` int DEFAULT NULL,
  `genero_principal` int DEFAULT NULL,
  `ano_formacao` int DEFAULT NULL,
  `ano_encerramento` int DEFAULT NULL,
  `biografia` text,
  `site_oficial` varchar(255) DEFAULT NULL,
  `imagem_url` varchar(512) DEFAULT NULL,
  `ativo` tinyint(1) DEFAULT '1',
  `criado_em` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `atualizado_em` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`artista_id`),
  KEY `fk_artistas_pais` (`pais_origem`),
  KEY `fk_artista_genero` (`genero_principal`),
  CONSTRAINT `fk_artista_genero` FOREIGN KEY (`genero_principal`) REFERENCES `tb_generos` (`genero_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_artistas_pais` FOREIGN KEY (`pais_origem`) REFERENCES `tb_paises` (`pais_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=536 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

