INSERT INTO `tb_artistas` VALUES (1,'The Beatles',97,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-25 16:16:51',NULL),(2,'The Rolling Stones',97,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-25 20:11:12',NULL),(3,'David Bowie',97,2,1962,2016,'Falar de David Bowie é entrar em um território onde biografia e reinvenção artística se confundem. Nascido como David Robert Jones, em 8 de janeiro de 1947, no bairro de Brixton, em London, Bowie construiu uma trajetória que desafia qualquer tentativa de linearidade. Sua vida não foi apenas uma sequência de álbuns e fases estéticas — foi um experimento contínuo sobre identidade, arte e cultura pop.\r\n\r\nDesde cedo, Bowie demonstrou inquietação criativa. Ainda adolescente, mergulhou em música, teatro e artes visuais, absorvendo influências que iam do rock ao jazz. Nos anos 1960, após algumas tentativas iniciais pouco expressivas, encontrou sua primeira grande virada com a canção *Space Oddity* (1969), lançada no contexto da Apollo 11 Moon Landing. A música não apenas o colocou no mapa, como já revelava sua tendência de dialogar com o zeitgeist — o espírito do tempo — transformando-o em arte.\r\n\r\nA década de 1970 foi o período mais emblemático de sua carreira, marcada por reinvenções radicais. Bowie não era apenas um músico: era um criador de personas. A mais famosa delas, Ziggy Stardust, surgiu com o álbum *The Rise and Fall of Ziggy Stardust and the Spiders from Mars*. Ziggy era um alienígena andrógino, um messias do rock que refletia tanto o glamour quanto a decadência da fama. Com ele, Bowie redefiniu os limites da performance musical, incorporando teatralidade, moda e narrativa em seus shows.\r\n\r\nMas Bowie nunca permaneceu em um único papel por muito tempo. Após o auge glam, mergulhou em sonoridades mais experimentais e sombrias. Em parceria com Brian Eno, criou a chamada “Trilogia de Berlim” — composta por álbuns como *Low* e *Heroes*. Gravados parcialmente em Berlin, esses trabalhos exploraram música eletrônica e ambient, influenciando gerações futuras. A faixa-título “Heroes” se tornaria um de seus hinos mais duradouros, simbolizando resistência e esperança em um contexto de Guerra Fria.\r\n\r\nNos anos 1980, Bowie alcançou sucesso comercial massivo com álbuns como *Let\'s Dance*. A faixa-título, produzida por Nile Rodgers, levou seu som a um público ainda mais amplo. No entanto, essa fase também levantou questionamentos críticos sobre uma possível “domesticação” de sua ousadia artística — algo que o próprio Bowie reconheceria mais tarde.\r\n\r\nA partir dos anos 1990, ele voltou a experimentar, explorando música eletrônica, industrial e até drum and bass. Bowie parecia sempre estar alguns passos à frente, antecipando tendências e recusando-se a ser uma relíquia de si mesmo. Sua atuação também se estendeu ao cinema, com papéis marcantes em filmes como *The Man Who Fell to Earth*, reforçando sua presença multifacetada.\r\n\r\nNos últimos anos de vida, Bowie manteve sua aura enigmática. Após um período relativamente discreto, retornou com o álbum *Blackstar*, lançado apenas dois dias antes de sua morte, em 10 de janeiro de 2016. O disco, permeado por reflexões sobre mortalidade, foi imediatamente reinterpretado como uma despedida artística cuidadosamente elaborada.\r\n\r\nComo resenha de sua vida, é impossível não reconhecer Bowie como um arquiteto da própria identidade. Ele não apenas acompanhou as transformações culturais do século XX — ele as provocou. Sua capacidade de se reinventar constantemente antecipou debates contemporâneos sobre gênero, autenticidade e performatividade. Bowie não foi apenas um músico influente; foi um conceito em movimento.\r\n\r\nNo fim das contas, analisar David Bowie é aceitar que sua biografia não cabe em categorias fixas. Ele foi, ao mesmo tempo, produto e criador de seu tempo — um artista que transformou a própria existência em obra de arte.\r\n','https://www.davidbowie.com/','https://i.discogs.com/Nc1FSm4J27mP2ZdvaR9uluSd7T8Vhn6uf5jw2SHdI3I/rs:fit/g:sm/q:90/h:591/w:598/czM6Ly9kaXNjb2dz/LWRhdGFiYXNlLWlt/YWdlcy9BLTEwMjYz/LTEzNDA4NzIyMTMt/OTc4MC5qcGVn.jpeg',1,'2025-04-25 20:13:10','2026-04-25 17:13:28'),(4,'The Doors',66,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-25 20:16:11',NULL),(5,'Miles Davis',66,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-25 20:17:41',NULL),(6,'The Beach Boys',66,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-25 20:20:14',NULL),(7,'Pink Floyd',97,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 15:26:32',NULL),(8,'Bee Gees',14,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 15:49:21',NULL),(9,'Big Brother & the Holding Company',97,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 15:53:45',NULL),(10,'Raul Seixas',28,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 15:57:41',NULL),(11,'Deep Purple',97,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 16:01:33',NULL),(12,'Jethro Tull',97,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 16:05:49',NULL),(13,'George Harrison',97,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 16:16:21',NULL),(14,'Neil Young',36,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 16:35:13',NULL),(15,'Genesis',97,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 16:39:42',NULL),(16,'Elton John',97,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 17:59:21',NULL),(17,'Yes',97,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 18:11:27',NULL),(18,'Janis Joplin',66,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 18:11:27',NULL),(19,'Led Zeppelin',97,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 18:11:27',NULL),(20,'John Lennon',97,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 18:11:27',NULL),(21,'Black Sabbath',97,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 18:11:27',NULL),(22,'Rita Lee',28,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 18:11:28',NULL),(23,'Paul McCartney',97,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 18:11:28',NULL),(24,'Supertramp',97,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 18:11:28',NULL),(25,'Eric Clapton',97,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-28 18:11:28',NULL),(26,'Santana',129,NULL,NULL,NULL,NULL,NULL,NULL,1,'2025-04-