--
-- Table structure for table `tb_midias`
--

DROP TABLE IF EXISTS `tb_midias`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tb_midias` (
  `midia_id` int NOT NULL AUTO_INCREMENT,
  `album_id` int NOT NULL COMMENT 'Referência à tb_albuns (antigo store_id)',
  `gravadora_id` int DEFAULT NULL,
  `formato_id` int DEFAULT NULL,
  `data_aquisicao` date NOT NULL,
  `numero_catalogo` varchar(100) DEFAULT NULL,
  `preco` decimal(10,2) DEFAULT NULL,
  `condicao` varchar(50) DEFAULT NULL,
  `observacoes` text,
  `data_ultima_execucao` datetime DEFAULT NULL,
  `discogs_id` int DEFAULT NULL,
  `criado_em` datetime DEFAULT CURRENT_TIMESTAMP,
  `atualizado_em` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `ativo` tinyint(1) NOT NULL DEFAULT '1',
  PRIMARY KEY (`midia_id`),
  KEY `idx_midia_album` (`album_id`),
  KEY `fk_midia_formato` (`formato_id`),
  KEY `fk_midia_gravadora_idx` (`gravadora_id`),
  CONSTRAINT `fk_midia_album` FOREIGN KEY (`album_id`) REFERENCES `tb_albuns` (`album_id`) ON DELETE CASCADE,
  CONSTRAINT `fk_midia_formato` FOREIGN KEY (`formato_id`) REFERENCES `tb_formatos` (`formato_id`) ON DELETE SET NULL,
  CONSTRAINT `fk_midia_gravadora` FOREIGN KEY (`gravadora_id`) REFERENCES `tb_gravadoras` (`gravadora_id`)
) ENGINE=InnoDB AUTO_INCREMENT=371 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `tb_midias`
--

LOCK TABLES `tb_midias` WRITE;
/*!40000 ALTER TABLE `tb_midias` DISABLE KEYS */;
INSERT INTO `tb_midias` VALUES (1,4169,1,1,'1986-08-30','144.500',30.00,NULL,'Esse foi meu primeiro álbum. Eu o comprei certa vez, quando tive de ir ao centro de São Paulo comprar uns ítens para realizar um trabalho da escola. Meu amigo Jonielson estava comigo. Também, nesse dia, assistimos ao filme Stallone: Cobra e fomos ao McDonald\'s. Quando voltamos pra casa fomos ouvir o disca na casa do Johnny, já que eu não tinha onde ouvi-lo.','2026-06-27 19:31:59',1463393,'2026-03-08 00:07:35','2026-06-27 19:31:59',1),(2,7512,2,1,'1986-12-09','530.039',18.36,NULL,'Esse álbum foi um presente de amigo secreto, recebido na 7a. série, de uma colega de sala chama Luciana Alves.','2026-06-27 19:32:02',1788971,'2026-03-08 22:36:20','2026-06-27 19:32:02',1),(5,4168,1,1,'1986-12-22','144.478',38.07,NULL,'Esse álbum foi comprado em um dia em que fui fazer serviços bancários para o meu tio, que era dono de um boteco/mercearia, no Jardim 9 de Julho, em São Paulo. A loja ficava no final da av. Mateo Bei, em São Mateus, próximo a antiga agência do Banespa.','2026-06-27 19:32:04',1463388,'2026-03-23 18:23:39','2026-06-27 19:32:04',1),(6,4227,3,1,'1987-07-18','670.4011',90.27,NULL,'Esse álbum foi comprado 3 vezes, em LP, de tanto que eu ouvia. É claro que pelo menos uma das vezes, a recompra aconteceu porque riscaram várias músicas dele, possivelmente, um dos meus irmãos. Foi a porta de entrada para o mundo do U2, que invadiu as fms em 1987, com força total.','2026-06-27 20:20:56',1123064,'2026-03-23 18:45:37','2026-06-27 20:20:56',1),(7,4032,4,1,'1987-08-21','610.7054',55.00,NULL,'Esse álbum foi comprado em uma loja de discos que havia em uma das saídas do metrô República, possivelmente em um dia de pagamento ou vale, na hora do almoço. Eu não conhecia o a-ha ainda. Foi um colega, Ronaldo Aleixo, quem indicou. Estámos os quatro cavaleiros do apocalipse juntos: eu, Ronaldo, Richie e Osmair. Todos office boys da Alta Veículos.','2026-06-28 15:35:56',NULL,'2026-03-24 19:04:53','2026-06-28 15:35:56',1),(8,4224,3,1,'1987-12-01','604.7149',90.00,NULL,'Antes de comprar esse álbum eu assiti ao home vídeo dele na casa do meu amigo Johnny. Aquele do álbum Rádio Pirata Ao Vivo.','2026-06-28 17:16:05',NULL,'2026-03-24 20:16:18','2026-06-28 17:16:05',1),(9,4033,4,1,'1987-12-20','610.7093',41.00,NULL,'A compra desse álbum foi um evento. Fomos ao cinema, eu e a galera, assistir uma noite alucinante. Depois do cinema e do bom e velho McDonalds, uma pequena visitinha a loja de discos para adquirir especificamente essa cópia. E na volta foi uma das maiores zonas que eu já participei em um busão.','2026-06-28 18:05:04',NULL,'2026-03-25 19:20:49','2026-06-28 18:05:04',1),(10,4223,3,1,'1987-12-28','610.7049',109.00,NULL,'Álbum comprado na saudosa Mesbla, na rua 24 de maio, no centro de São Paulo.','2026-06-28 18:14:38',13394228,'2026-03-25 19:48:13','2026-06-28 18:14:38',1),(11,88,5,1,'1987-12-28','064 400165',249.00,NULL,'Esse álbum foi adquirido junto com War, do U2, na Mesbla.','2026-03-27 18:33:55',NULL,'2026-03-26 19:22:54','2026-03-27 18:33:55',1),(12,7514,2,1,'1988-01-08','590.001',30.00,NULL,'Esse álbum não tem nenhuma hsitória, mas era a forma que a gente tinha na época de ter acesso ao que fazia sucesso nas rádios. Muitas das músicas que eram publicadas nas trilhas sonoras de novela só chegavam ao país dessa forma. O álbum nunca era lançado aqui, então ou gravávamos a música na rádio ou comprávamos discos de novela.','2026-03-27 19:38:26',NULL,'2026-03-27 18:40:22','2026-03-27 19:38:26',1),(13,7515,2,1,'1988-01-20','530.030',30.00,NULL,'',NULL,NULL,'2026-03-27 19:45:59','2026-05-30 15:01:05',1),(14,4221,3,1,'1988-02-05','610.7089',96.00,NULL,'Eu descobri o U2 bem no começo da minha coleção e a banda se tornou uma obsessão. Basta ver a quantidade de álbuns do U2 frente as outras bandas.',NULL,NULL,'2026-03-27 23:35:50','2026-03-27 23:36:54',1),(15,4226,3,1,'1988-03-17','604.7177',70.00,NULL,'',NULL,1123052,'2026-03-27 23:55:38','2026-03-27 23:55:38',1),(16,1698,6,1,'1988-04-08','304.7067',142.50,NULL,'Até hoje eu não entendo o porque eu comprei esse álbum. Eu sei que ele foi comprado em uma banca de coisas encostadas, do tipo que ninguém quer, e deve ter sido uma pechinha. Mas acredito que deve ter sido por causa da música Under Milk Away, mas como eu não sabia o nome, o primeiro disco que eu encontrei que tinha escrito The Church, eu comprei.',NULL,NULL,'2026-03-28 00:03:15','2026-03-28 00:03:56',1),(17,4225,3,1,'1988-05-06','610.7042',87.00,NULL,'Outro disco do U2? Sim, mas houveram outros discos que não estão mais aqui. Alguns foram vendidos, outros foram levados, e mais alguns perdidos. Mas não era só U2 que eu comprava.',NULL,11700231,'2026-03-28 00:16:47','2026-03-28 00:16:47',1),(18,3567,7,1,'1988-05-06','670.0078',44.00,NULL,'Esse álbum foi adquirido por causa da música Foolish Beat, que estava estourada nas FMs. Como eu, junto com meu amigo Botinha, estávamos metidos a DJs, e todo bailinho tem a hora das músicas lentas, esse disco seria sucesso garantido.',NULL,NULL,'2026-03-28 10:45:43','2026-03-28 11:11:17',1),(19,2234,9,1,'1988-05-20','066 748513 1',50.00,NULL,'Álbum adquirido em um sebo que ficava no início da Rua Agusta, quase no centro de São Paulo, durante um momento de enrolação em horário de trabalho. Já tinha terminado o serviço antes do esperado e fiquei passeando pelas lojas do lugar, e nessa loja de discos encontrei o álbum dando sopa por um preço irresistível.',NULL,1672126,'2026-03-28 11:09:47','2026-03-28 11:09:47',1),(20,1847,10,1,'1988-06-10','670.4013',175.00,NULL,'Esse não foi o meu primeiro álbum do Depeche Mode. O primeiro foi Music For the Masses, e ele cai naquela história dos vendidos, surrupiados, desaparecidos. E como eu já conhecia,e amava, o som da banda, quando ouvi a música Black Celebration na rádio, sai como um louco atrá do álbum.',NULL,2258425,'2026-03-28 11:22:40','2026-03-28 11:22:40',1),(21,4034,4,1,'1988-07-19','670.4135',30.00,NULL,'Quando esse disco foi lançado, ele se tornou onipresente em cartazes nas ruas, nas lojas, na fms. Não tinha como se livrar dele. E eu, fã desvairado da banda, corri comprar. Logo nos primeiros dias minha irmã riscou a faixa \'You Are The One\'. Pensa na fúria, na raiva, na decepção. Mas não comprei outra cópia, porque esse LP era caro. E também pouco ouvi depois do dano. Só fui fazer as pazes com esse álbum muitos anos depois quando o adquiri em CD. E o trauma do risco é tão grande, que mesmo ouvindo no CD eu ainda fico esperando o pulo.',NULL,1377550,'2026-03-28 11:35:21','2026-03-28 11:35:21',1),(22,1914,12,1,'1988-08-11','670.0022',75.00,NULL,'Pérola do anos 80. Junto com U2, a-ha e Depeche Mode, a outra banda que ajudou a definir o meu estilo naquela época. Esse disco não era meu. Ele apareceu em casa trazido pelo Bacana, sei lá de onde, junto com 3 - Live in the City of Light, True Colors e Madonna. E ficaram fazendo parte da minha coleção por muito tempo. Um dia o Bacana apareceu querendo os discos de volta. Eu só estava com o da Cyndi e da Madonna. Por sorte, Brotherhood e In the City estavam com o Botinha. -Depois eu venho buscar os outros. Já se passaram quase 40 anos.',NULL,651696,'2026-03-28 11:46:00','2026-03-28 11:46:00',1),(23,1398,13,1,'1988-08-11','122.8002',90.00,NULL,'Esse é o outro LP sobrevivente ao confisco do Bacana.',NULL,7316113,'2026-03-28 15:31:50','2026-03-28 15:31:50',1),(24,3743,14,1,'1989-03-10','230.4008',90.00,NULL,'Ente muitas influências musicais que sofri no decorrer da minha vida, esse álbum é o segundo fruto dessas influências. O primeiro tinha sido o Hunting High and Low (Ronaldo Aleixo). E agora o Ritchie (Ricardo de Matos Santana) e o autor desse álbum. Tocou muito nas minhas festinhas pelo bairro. A galera pirava com Beat Dis.',NULL,990420,'2026-03-28 15:42:00','2026-03-28 15:42:00',1),(25,1741,9,1,'1989-03-10','066 790958 1',35.00,NULL,'Pensa numa banda que falava a língua dos anos 80. E esse foi o primeiro álbum que eu adquiri do caras, já no final da fase áurea deles, porque tinha duas músicas no álbum bombando nas pistas de dança: All She Want Is e I Don\'t Want Your Love. Originalmente adquirido em K7, só mais tarde comprado em LP.',NULL,1632899,'2026-03-28 15:50:12','2026-03-28 15:50:12',1),(26,1863,10,1,'1989-04-07','670.8026',130.00,NULL,'Encantado pelo som do Depeche Mode e sem nenhum outro álbum da discografia deles disponível no Brasil, o jeito foi apelar para essa coletânea.',NULL,649420,'2026-03-28 16:01:44','2026-03-28 16:01:44',1),(27,3593,15,1,'1986-05-05','310.6015',59.00,NULL,'Álbum comprado errado. A música que me levou a comprar esse disco estaria no álbum \'Sombras na Calçada\'. Mas eu achava que os caras estavam estreando, então esse seria o certo.',NULL,20260375,'2026-03-28 17:49:50','2026-03-28 17:49:50',1),(28,3766,16,1,'1989-06-09','670.4110',139.00,NULL,'Esse é outro álbum adquirido pela influência do Ritchie. Eu ouvi na casa dele e achei espetacular. Principalmente o clima anos 60 do álbum.',NULL,2766183,'2026-03-28 20:09:07','2026-03-28 20:09:07',1),(29,1915,12,1,'1989-07-05','670.9010',70.00,NULL,'Meu álbum preferido do New Order. E como já aconteceu com o Depeche Mode, esse também não é o segundo que eu comprava. Teve outros que sumiram no vento, e que mais tarde eu comprei em cd.',NULL,NULL,'2026-03-29 12:45:00','2026-03-29 12:46:06',1),(30,7516,16,1,'1989-08-19','670.8084',65.00,NULL,'O álbum da carinha da Doriana. Fez muita gente balançar o esqueleto.',NULL,NULL,'2026-03-29 13:00:35','2026-03-29 13:04:03',1),(31,3330,17,1,'1989-11-29','066 790868 1',68.00,NULL,'Amava o som do Pet Shop Boys, como amava New Order e Depeche Mode, mas Instrospective foi a primeira oportunidade de ter um álbum dos fulanos. E esse ainda fazia sucesso nas festinhas, pra ajudar na escolha.',NULL,NULL,'2026-03-29 13:24:00','2026-03-29 13:28:21',1),(32,3328,17,1,'1989-12-01','066 240666 1',80.00,NULL,'E na esteira de Introspective veio Disco. Como eu não achava os álbuns Please e Actually, me contentei com ele.',NULL,584545,'2026-03-29 13:40:54','2026-03-29 13:40:54',1),(33,3045,10,1,'1989-12-01','670.4269',58.00,NULL,'Como alguns outros álbuns, esse não é o primeiro da banda. No caso do Erasure, eu já tinha The Innocents. Esse EP foi adquirido na fase que eu costumo chamar de \'Explosão Eletrônica\'. A fase que eu era metido a DJ e estava em tudo quanto era festinha. Esse disco foi adquirido por cauda da música Stop!',NULL,NULL,'2026-03-30 19:00:05','2026-04-27 21:23:59',1),(34,1858,10,1,'1989-12-02','675.5002',135.00,NULL,'Esse álbum não ia pra festinhas. Era uma das pérolas da coleção. Não emprestava pra ninguém. E por ser um álbum duplo, custou cara bagaria. Acha que ia correr o risco?',NULL,NULL,'2026-03-30 19:40:54','2026-04-27 21:23:08',1),(35,3410,19,1,'1989-12-07','150.4006',80.00,NULL,'Eu comprei esse disco só por causa da música Def.Con.One, mas fiquei decepcionado porque a versão do disco não tem nenhum trabalho de remix. É a versão crua.',NULL,2256463,'2026-04-02 19:01:23','2026-04-02 19:01:23',1),(36,1386,13,1,'1989-12-07','068 427005 1',30.00,NULL,'',NULL,NULL,'2026-04-02 19:55:45','2026-04-02 21:45:14',1),(37,7518,20,1,'1989-12-19','066 790380 1',75.00,NULL,'',NULL,2852018,'2026-04-02 21:49:14','2026-04-02 21:49:14',1),(38,6124,17,1,'1990-01-18','064 791732 1',40.00,NULL,'',NULL,2529731,'2026-04-03 17:37:46','2026-04-03 17:37:46',1),(39,7544,2,1,'1990-02-17','405.0006',35.00,NULL,'',NULL,2486411,'2026-04-03 19:41:05','2026-04-03 19:41:05',1),(40,1777,21,1,'1990-03-06','670.8138',100.00,NULL,'',NULL,3601908,'2026-04-03 22:19:29','2026-04-03 22:19:29',1),(41,7545,22,1,'1990-06-08','840.103',99.00,NULL,'Pensa num disco comprado apenas por causa de uma música e só. Nunca tinha ouvido esse disco até o meu retorno às raízes da mídia física, e o consequente resgate dele da casa da minha mãe, no final de 2022. E ele nem é tão intragável. Dá pra ouvir, não vendo a hora de acabar, kkkk',NULL,3286762,'2026-04-03 23:52:34','2026-04-03 23:52:34',1),(42,4012,14,1,'1990-07-10','230.4015',65.00,NULL,'Pensa num álbum que demorou pra sair aqui. Já tinha músicas dele espelhadas por todas as coletâneas que você possa imaginar. Eu mesmo tinha um disco pirata com Walking Away, comprada na galeria do Rock, em uma versão que eu nunca ouvi nas pistas. Já tinha uma fita gravada na Manchete FM, com todas as músicas, e só não tinha o álbum, lançado por uma gravadora indenpendente, amém!',NULL,194779,'2026-04-04 14:11:43','2026-04-04 14:11:43',1),(43,7546,2,1,'1990-07-20','407.0018',40.00,NULL,'',NULL,3485509,'2026-04-04 14:18:05','2026-04-04 14:18:05',1),(44,7547,2,1,'1990-08-11','407.0004',20.00,NULL,'',NULL,4325218,'2026-04-04 14:36:44','2026-04-04 14:36:44',1),(45,7548,7,1,'1990-09-06','670.8098',65.00,NULL,'',NULL,194784,'2026-04-04 14:54:16','2026-04-04 14:54:16',1),(46,7551,23,1,'1990-10-05','140.8075',90.00,NULL,'',NULL,10763431,'2026-04-04 15:02:14','2026-04-04 15:02:14',1),(47,7552,16,1,'1990-12-07','670.9235',100.00,NULL,'Presente de aniversário dos colegas da ALTA Vaículos',NULL,2661707,'2026-04-04 15:13:07','2026-04-04 15:13:07',1),(48,4013,14,1,'1990-12-07','492.009',56.00,NULL,'',NULL,1222019,'2026-04-04 15:21:45','2026-04-04 15:21:45',1),(49,3331,17,1,'1990-12-07','068 794310 1',55.00,NULL,'Outro presente da turma da Alta. Eu acho que eu era querido, apesar de ser um mala, hehe.',NULL,584549,'2026-04-04 15:28:16','2026-04-04 15:28:16',1),(50,1756,9,1,'1990-12-21','066 793577 1',60.00,NULL,'',NULL,1953560,'2026-04-04 15:38:00','2026-04-04 15:38:00',1),(51,4035,4,1,'1991-01-18','670.8196',114.00,NULL,'',NULL,3235879,'2026-04-04 15:44:23','2026-04-04 15:44:23',1),(52,2979,24,1,'1991-02-15','828 238-1',180.00,NULL,'',NULL,NULL,'2026-04-04 15:49:38','2026-04-04 15:50:24',1),(53,7553,25,1,'1991-03-09','920 565 1',100.00,NULL,'',NULL,NULL,'2026-04-04 17:46:32','2026-04-04 17:49:20',1),(54,2030,26,1,'1991-03-23','412.082',140.00,NULL,'',NULL,1463382,'2026-04-05 13:27:38','2026-04-05 13:27:38',1),(55,2199,1,1,'1991-04-18','144.504',25.00,NULL,'',NULL,NULL,'2026-04-05 14:36:30','2026-04-05 14:37:04',1),(56,4285,27,2,'1992-01-07','GEFD 24415',39.00,NULL,'Os dois Use Your Illusion\'s foram meus primeiros CDs, adquiridos na Lojas Americanas da rua Direita, no centro de Sâo Paulo, em uma promoção em que os 2 CDs estavam mais baratos que apenas um dos LPs. Como eu já tinha gastado uma grana nos dois LPs, que, naquela altura, foram os últimos que eu comprei, eu os vendi ao saudoso Silvio Crispim.',NULL,NULL,'2026-04-05 14:49:24','2026-04-06 18:55:51',1),(57,4286,27,2,'1992-01-07','GEFD 24420',44.00,NULL,'Os dois Use Your Illusion\'s foram meus primeiros CDs, adquiridos na Lojas Americanas da rua Direita, no centro de Sâo Paulo, em uma promoção em que os 2 CDs estavam mais baratos que apenas um dos LPs. Como eu já tinha gastado uma grana nos dois LPs, que, naquela altura, foram os últimos que eu comprei, eu os vendi ao saudoso Silvio Crispim.',NULL,14548310,'2026-04-05 14:53:41','2026-04-05 14:53:41',1),(58,5226,9,2,'1992-01-17','748209 2',45.00,NULL,'',NULL,14302054,'2026-04-05 19:19:17','2026-04-05 19:19:17',1),(59,3583,7,2,'1992-02-05','782242-2',75.00,NULL,'',NULL,NULL,'2026-04-06 18:26:04','2026-04-06 18:57:22',1),(60,1241,4,2,'1992-03-06','926594-2',60.00,NULL,'',NULL,372004,'2026-04-06 18:37:49','2026-04-06 18:37:49',1),(61,4229,3,2,'1992-05-08','510 347-2',30.00,NULL,'',NULL,443164,'2026-04-06 18:54:21','2026-04-06 18:54:21',1),(62,1642,16,2,'1992-06-05','M 172550-2',30.00,NULL,'',NULL,NULL,'2026-04-06 19:04:59','2026-04-06 19:04:59',1),(63,5228,9,2,'1992-08-03','368 748820 2',30.00,NULL,'CD comprado pra substituir o LP Que País É Este, que sumiu, desapareceu, escafedeu-se.',NULL,16087216,'2026-04-06 19:38:25','2026-04-06 19:38:25',1),(64,3854,28,2,'1992-09-21','752.100/2- 467201',35.00,NULL,'',NULL,13058623,'2026-04-06 20:36:53','2026-04-06 20:36:53',1),(65,3595,1,2,'1992-10-16','700.012',56.00,NULL,'Esse CD era de um companheiro de exército, Aparecido, que eu emprestei uns K7s com músicas do Metallica e ele nunca me devolveu. Então eu pedi o CD emprestado e nunca devolvi.',NULL,NULL,'2026-04-07 19:03:36','2026-04-07 19:20:04',1),(66,1344,28,2,'1993-04-24','700.455/2-465653',31.00,NULL,'',NULL,NULL,'2026-04-07 19:19:03','2026-04-07 19:19:28',1),(67,4228,3,2,'1993-05-07','842 299-2',35.00,NULL,'Cd adquirido para substituir o LP, que sumiu, desapareceu, escafedeu-se.',NULL,443171,'2026-04-08 18:23:59','2026-04-08 18:23:59',1),(68,1625,29,2,'1993-10-19','510 580-2',30.00,NULL,'Queria ter comprado esse álbum na época do seu lançamento. Ele vinha em um estojo com várias coisas legais, inclusive com o calendário da turnê. Mas não deu. Quando comprei, logo ele foi danificado, e algumas músicas do começo do álbum não tocavam. Muitos anos depois, quando comprei outro exemplar, ele estava riscado, mas, dependendo do aparelho, tocava de boa. Aí comprei esse derradeiro, que toca de cabo-a-rabo.',NULL,NULL,'2026-04-08 18:33:06','2026-04-08 18:47:12',1),(69,2492,28,2,'1993-12-13','752.206/2-472253',35.00,NULL,'',NULL,7644571,'2026-04-08 18:38:59','2026-04-08 18:38:59',1),(70,3507,24,2,'1993-12-20','828 307-2',30.00,NULL,'',NULL,655538,'2026-04-08 18:44:32','2026-04-08 18:44:32',1),(71,1092,29,2,'1993-12-24','832 464-2',80.00,NULL,'No final de 1993 eu arranjei um trabalho temporário, de final de ano, no Shopping Aricanduva, como vendedor de uma loja de discos chamada Fillipo\'s Discos. No final da temporada de trabalho eu comprei Hold Your Fire. Meu primeiro passo rumo ao mundo do Rush.',NULL,428379,'2026-04-08 18:54:03','2026-04-08 18:54:03',1),(72,5232,9,2,'1993-12-24','835 838 2',25.00,NULL,'Originalmente, esse disco era do Regi, meu irmão. Quando eu me muei pra Rio Preto e tivemos de dividir nossa coleção, ele ficou com o item, claro. Anos depois eu comprei essa cópia para preencher o vazio deixado por aquele primeiro álbum.',NULL,459443,'2026-04-08 19:00:12','2026-04-08 19:00:12',1),(73,1343,28,2,'1994-01-29','700.545/2-460005',50.00,NULL,'Depois do trabalho, as férias. Logo após ter encerrado meu trabalho temporário na Fillipo\'s Discos eu fui para Colorado. Um dia, eu e mes primos Márcio e Perdigão, vulgo Celso, fomos para Maringá. Depois de encher o bucho com chocolates adquiridos na Lojas Americanas, também comprei esse CD. Os chocolates, não o CD, me renderam uma alergia desgraçada. Também, comi todos os chocolates do estoque da loja, kkkk.\r\nUm detalhe curioso sobre esse CD é que, apesar do encarte informar 11 músicas, ele só tem 10. A música inexistente é Gunbarrel Highway.',NULL,NULL,'2026-04-08 19:12:44','2026-04-08 19:15:42',1),(74,1089,29,2,'1994-04-18','810 002-2',125.00,NULL,'Quando eu comprei esse álbum, na galeria do Rock, em São Paulo, fiquei na dúvida entre ele e o Grace Under Pressure. Depois me arrependi e achei que deveria ter ficado com o outro. Hoje tenho os dois, pra não restar mais dúvidas.',NULL,1817599,'2026-04-08 19:20:33','2026-04-08 19:20:33',1),(75,1103,30,2,'1994-04-18','836 346-2',91.00,NULL,'Esse CD foi adquirido porque eu estava sedento por Rush, mas não sabia o que comprar. Ele serviu para me dar um norte por um tempo, já que o Rush não era uma banda de tocar muito no rádio.',NULL,1822433,'2026-04-08 19:25:27','2026-04-08 19:25:27',1),(76,1095,7,2,'1994-07-01','7567825282',36.00,NULL,'Esse CD era de uma locadora que ficava na Av. Paes de Barros. Um dia fui lá pra alugar e eles não tinham energia e não estavam registrando os cds que estavam saindo. Nunca mais voltei. E não me orgulho disso.',NULL,522115,'2026-04-09 18:09:36','2026-04-09 18:09:36',1),(77,946,27,2,'1995-02-13','GEFD 24546',30.00,NULL,'Esse CD tem uma falha nas música Blind Man/Deuces Are Wild, de fábrica. Comprei o CD na Lojas Americanas e nunca voltei pra trocá-lo. Qualquer dia desses eu faço a troca.',NULL,6448129,'2026-04-09 18:24:04','2026-04-09 18:24:04',1),(78,1926,24,2,'1995-05-22','398428228 2',30.00,NULL,'',NULL,221522,'2026-04-09 18:34:38','2026-04-09 18:34:38',1),(79,4402,1,2,'1995-10-16','752.099/2-468884',31.00,NULL,'Presente